class Solution:
    def subarrayGCD(self, nums: List[int], k: int) -> int:
        count = 0
        for i in range(len(nums)):
            gcd = nums[i]
            for j in range(i, len(nums)):
                gcd = self.gcd(gcd, nums[j])
                if gcd == k:
                    count += 1
                elif gcd < k:
                    break
        return count

    def gcd(self, a: int, b: int) -> int:
        while b:
            a, b = b, a % b
        return a
